parameters.jsCode:
const raw = $input.first().json.text || '';

// Strip markdown code fences if model wraps in ```json
const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  // Fallback: return raw so we can debug
  return [{ json: { titulo: 'Error de parseo', historia: raw, hashtags: '', prompt_imagen: '', error: e.message } }];
}

return [{
  json: {
    titulo:        parsed.titulo        || '',
    historia:      parsed.historia      || '',
    hashtags:      parsed.hashtags      || '',
    prompt_imagen: parsed.prompt_imagen || '',
    hombre:        $('Random Variables').first().json.hombre,
    situacion:     $('Random Variables').first().json.situacion,
    lugar:         $('Random Variables').first().json.lugar,
    relacion:      $('Random Variables').first().json.relacion,
    tono:          $('Random Variables').first().json.tono,
    intensidad:    $('Random Variables').first().json.intensidad,
    cta:           $('Random Variables').first().json.cta,
    fecha:         $now.toISO()
  }
}];
